-- 快速自检
SELECT
  MIN(data_time) AS min_time,
  MAX(data_time) AS max_time,
  COUNT(*) AS total_count,
  SUM(CASE WHEN status = '1' THEN 1 ELSE 0 END) AS unprocessed_count,
  SUM(CASE WHEN status = '2' THEN 1 ELSE 0 END) AS processed_count,
  SUM(CASE WHEN level = 1 THEN 1 ELSE 0 END) AS level1_count,
  SUM(CASE WHEN level = 2 THEN 1 ELSE 0 END) AS level2_count,
  SUM(CASE WHEN level = 3 THEN 1 ELSE 0 END) AS level3_count
FROM alarm
WHERE remark = 'AutoGeneratedAlarm0331';
